// Uses Kotlin's standard random library
import kotlin.random.Random // Import Random

fun main() {
    // Default random number generator instance
    val random = Random.Default

    // Generate a random integer (Int.MIN_VALUE to Int.MAX_VALUE)
    val randomInt = random.nextInt()
    println("Random Integer (full range): ${randomInt}") // Kotlin String template

    // Generate a random integer within a specific range [min, max] (inclusive)
    val minVal = 1
    val maxVal = 100
    // Use until for exclusive upper bound: random.nextInt(minVal, maxVal + 1)
    // Or use range directly:
    val randomInRange = (minVal..maxVal).random() // Get random element from IntRange
    println("Random Integer [${minVal}-${maxVal}]: ${randomInRange}")

    // Generate a random double between 0.0 (inclusive) and 1.0 (exclusive)
    val randomDouble = random.nextDouble()
    println("Random Double [0.0, 1.0): ${randomDouble}")

    // Select a random element from a list or array
    val fruits = listOf("apple", "banana", "cherry")
    if (fruits.isNotEmpty()) {
        val randomFruit = fruits.random() // Use collection extension .random()
        println("Random fruit: ${randomFruit}")
    }

    // Using a specific seed
    val seededRandom = Random(12345)
    println("Seeded random int (1-6): ${seededRandom.nextInt(1, 7)}") // Upper bound is exclusive
}

