// Use BigInteger for arbitrary precision (requires JVM target or Kotlin/Native equivalent)
import java.math.BigInteger

// Calculates the Nth Fibonacci number (0-indexed) iteratively
fun fibonacci(n: Int): BigInteger {
    require(n >= 0) { "Input must be non-negative" } // Precondition check

    return when (n) {
        0 -> BigInteger.ZERO
        1 -> BigInteger.ONE
        else -> {
            var a = BigInteger.ZERO
            var b = BigInteger.ONE
            // Loop from 2 up to n
            for (i in 2..n) {
                val next = a + b
                a = b
                b = next
            }
            b
        }
    }
}

// Generates the first 'count' Fibonacci numbers as a List
fun generateFibonacciSequence(count: Int): List<BigInteger> {
     require(count >= 0) { "Count must be non-negative" }
     // Use map on range to apply fibonacci function
     return (0 until count).map { fibonacci(it) }
}

// Alternative using Sequence (lazy evaluation)
fun fibonacciSequenceLazy(): Sequence<BigInteger> = sequence {
    var a = BigInteger.ZERO
    var b = BigInteger.ONE
    while (true) {
        yield(a)
        val next = a + b
        a = b
        b = next
    }
}

fun main() {
    val n = 10
    println("Fibonacci number F(${n}): ${fibonacci(n)}")

    val numTerms = 15
    println("First ${numTerms} Fibonacci numbers:")
    val sequenceList = generateFibonacciSequence(numTerms)
    println(sequenceList.joinToString()) // Default list printing is good

    println("First 5 Fibonacci numbers (lazy sequence):")
    println(fibonacciSequenceLazy().take(5).toList().joinToString())

    // Example with large number
    val largeN = 90
    println("Fibonacci number F(${largeN}): ${fibonacci(largeN)}")
}

