import java.math.BigInteger // Use BigInteger for arbitrary size

// Function to calculate factorial N!

// Method 1: Iterative using a loop
fun factorialLoop(n: Int): BigInteger {
    require(n >= 0) { "Factorial input must be non-negative" }

    var result = BigInteger.ONE // Factorial of 0 is 1
    if (n == 0) return result

    for (i in 2..n) { // Loop from 2 to n (inclusive)
        // Use .multiply() or overloaded operator * for BigInteger if available
        result *= i.toBigInteger()
    }
    return result
}

// Method 2: Using fold on a range (functional style)
fun factorialFold(n: Int): BigInteger {
     require(n >= 0) { "Factorial input must be non-negative" }
     if (n == 0) return BigInteger.ONE

    // Fold the range (1..n) starting with BigInteger.ONE, multiplying along the way
    return (1..n).fold(BigInteger.ONE) { acc, i ->
        acc * i.toBigInteger()
    }
}

fun main() {
    val num = 5
    println("Factorial of ${num} (loop): ${factorialLoop(num)}")
    println("Factorial of ${num} (fold): ${factorialFold(num)}")

    val numZero = 0
    println("Factorial of ${numZero}: ${factorialLoop(numZero)}")

    val numLarge = 30 // Requires BigInteger
    println("Factorial of ${numLarge}: ${factorialLoop(numLarge)}")

    // Example invalid input
    try {
        factorialLoop(-3)
    } catch (e: IllegalArgumentException) {
        println("Error calculating factorial: ${e.message}")
    }
}

