import kotlin.math.sqrt // Import sqrt function

// Function to check if a number is prime
fun isPrime(n: Long): Boolean { // Use Long for larger range
    if (n <= 1) return false
    if (n <= 3) return true
    // Use Kotlin's % operator for remainder
    if (n % 2 == 0L || n % 3 == 0L) return false

    // Check factors from 5 upwards, stepping by 6
    val limit = sqrt(n.toDouble()).toLong() // Calculate long square root limit
    var i = 5L
    while (i <= limit) {
        if (n % i == 0L || n % (i + 2) == 0L) {
            return false // Divisor found
        }
        i += 6L
    }
    return true // No divisors found
}

fun main() {
    val numbersToCheck = listOf(2L, 3L, 4L, 17L, 25L, 29L, 97L, 100L, 1L, -5L, 1_000_000_007L) // L suffix for Long

    numbersToCheck.forEach { n -> // Use Kotlin's forEach extension
        if (isPrime(n)) {
            println("${n} is prime.")
        } else {
            println("${n} is not prime.")
        }
    }
}

