// Uses Kotlin standard library extensions for Java's File API (JVM target assumed)
import java.io.File
import java.io.IOException

fun main() {
    val filePath = "kotlin_read_test.txt"

    // Create a dummy file for reading
    try {
        val file = File(filePath)
        // Use writeText extension (overwrites, creates, uses UTF-8 by default)
        file.writeText("Line 1 content from Kotlin.\nThis is the second line.\nEnd.")
        println("Created dummy file '${filePath}' for reading.")
    } catch (e: Exception) {
         println("Error creating dummy file: ${e.message}")
         return // Cannot proceed
    }

    println("\n--- Reading file '${filePath}' ---")
    val file = File(filePath) // Create File object

    if (file.exists() && file.isFile) { // Use property access (isFile not isFile())
        try {
            // Method 1: Read all text into one string using '.readText()' extension
            println("\n--- Reading using file.readText() ---")
            val content = file.readText() // Reads entire file (UTF-8 default)
            println("File content as single string:")
            println(content)
            println("--- End of file.readText() ---")

            // Method 2: Read lines into a List<String> using '.readLines()' extension
            println("\n--- Reading using file.readLines() ---")
            val lines = file.readLines() // Reads lines into List (UTF-8 default)
            println("Read ${lines.size} lines:")
            lines.forEachIndexed { index, line -> // Use forEachIndexed extension
                println("Line ${index + 1}: ${line}")
            }
            println("--- End of file.readLines() ---")

            // Method 3: Process line by line using '.useLines' closure (ensures reader close)
            println("\n--- Reading using file.useLines ---")
            var lineNum = 1
            file.useLines { sequence -> // Provides a Sequence<String>
                sequence.forEach { line ->
                     println("Closure Line ${lineNum}: ${line}")
                     lineNum++
                 }
            }
            println("--- End of file.useLines ---")

        } catch (e: IOException) {
            println("An error occurred while reading the file: ${e.message}")
        } catch (e: Exception) {
             println("An unexpected error occurred: ${e.message}")
        } finally {
            // Clean up dummy file
            file.delete()
            println("\nCleaned up dummy file '${filePath}'.")
        }
    } else {
        println("Error: File not found or is not a regular file: '${filePath}'")
        // Attempt cleanup just in case
        if (file.exists()) { file.delete() }
    }
}

