import java.io.File
import java.io.IOException

fun main() {
    val filePath = "output_kotlin.txt"
    val initialLines = listOf(
        "First line written by Kotlin.",
        "Second line using writeText."
    )
    val lineToAppend = "Third line, appended using appendText."

    // --- Write using File.writeText() (overwrites or creates, UTF-8 default) ---
    println("--- Writing to '${filePath}' (overwrite) ---")
    try {
        val file = File(filePath)
        // Join lines with platform newline and write
        file.writeText(initialLines.joinToString(System.lineSeparator()) + System.lineSeparator())
        println("Successfully wrote initial content.")
    } catch (e: Exception) {
        println("Error writing to '${filePath}': ${e.message}")
    }

    // --- Append using File.appendText() ---
    println("\n--- Appending to '${filePath}' ---")
    try {
        val file = File(filePath)
        file.appendText(lineToAppend + System.lineSeparator()) // Appends text, adds newline
        println("Successfully appended content.")
    } catch (e: Exception) {
        println("Error appending to '${filePath}': ${e.message}")
    }

    // --- Display final content ---
    println("\n--- Final content of '${filePath}': ---")
    val readFile = File(filePath)
    if (readFile.exists() && readFile.isFile) {
      try {
          print(readFile.readText()) // Print entire file content
      } catch (e: Exception) {
          println("Error reading back file: ${e.message}")
      }
    } else {
      println("File '${filePath}' not found for display.")
    }

    // Optional: Clean up
    // File(filePath).delete()
}

