import java.io.File

fun main() {
    val fileToCheck = "kotlin_exists_test.kt"
    val dirToCheck = "MyKotlinFolder"
    val nonExistent = "NoSuchThingHereKt.xyz"

    // Create dummy file/dir using Kotlin extensions
    val fileObj = File(fileToCheck)
    val dirObj = File(dirToCheck)

    try {
        fileObj.writeText("// Kotlin test file") // Creates/overwrites
        dirObj.mkdirs() // Creates directory including parents if needed
        println("Created/Ensured dummy file '${fileToCheck}' and directory '${dirToCheck}'")
    } catch (e: Exception) {
        println("Error creating dummies: ${e.message}")
        return
    }


    println("\n--- Checking Existence and Type ---")

    // Use file.exists() property
    println("'${fileToCheck}' exists? ${fileObj.exists()}")     // true
    println("'${dirToCheck}' exists? ${dirObj.exists()}")      // true
    println("'${nonExistent}' exists? ${File(nonExistent).exists()}") // false

    // Use file.isFile property
    println("\n'${fileToCheck}' is file? ${fileObj.isFile}") // true
    println("'${dirToCheck}' is file? ${dirObj.isFile}")  // false

    // Use file.isDirectory property
    println("\n'${fileToCheck}' is directory? ${fileObj.isDirectory}") // false
    println("'${dirToCheck}' is directory? ${dirObj.isDirectory}")  // true


    // Clean up
    println("\nCleaning up...")
    try {
         fileObj.delete()
         dirObj.delete() // Deletes empty directory
         println("Cleaned up dummy file and directory.")
    } catch (e: Exception) {
         println("Error during cleanup: ${e.message}")
    }
}

