// Finding the maximum value in Kotlin Collections (List, Array, Sequence)

fun main() {
    // Example List<Int>
    val numbersList: List<Int> = listOf(10, 5, 42, 17, 8, 99, 32, -5, 0)
    println("List: ${numbersList}") // Kotlin lists print nicely

    // Use the .maxOrNull() extension function (returns null if empty)
    val maxValueList: Int? = numbersList.maxOrNull() // Type is nullable Int?

    if (maxValueList != null) {
        println("Maximum value (List): ${maxValueList}")
    } else {
        println("List is empty, cannot find maximum.")
    }

    // Finding the index
    if (maxValueList != null) {
       val maxIndex = numbersList.indexOf(maxValueList) // Finds first index
       println("Index of maximum value: ${maxIndex}")
    }

    println("\n--- Other Examples ---")
    // Example Array<String>
    val stringsArray: Array<String> = arrayOf("apple", "banana", "zebra", "cherry")
    println("String Array: ${stringsArray.joinToString()}") // Use joinToString for arrays
    val maxString: String? = stringsArray.maxOrNull()
    println("Maximum value (lexicographical): ${maxString ?: "Array is empty"}") // Elvis operator ?: for null default


    // Example empty list
    val emptyList: List<Int> = emptyList()
    println("\nEmpty list: ${emptyList}")
    val maxEmpty = emptyList.maxOrNull() // Returns null
    if (maxEmpty == null) {
         println("Cannot find maximum in empty list (maxOrNull returns null)." )
    }

    // Example Sequence<Double>
    val doubleSeq = sequenceOf(1.5, -0.5, 3.14, 2.71)
    println("\nSequence: ${doubleSeq.toList()}") // Realize for printing
    val maxDouble = doubleSeq.maxOrNull()
    println("Maximum value (Sequence): ${maxDouble ?: "Sequence is empty"}")
}
